1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellsEqual = ([x1, y1]: Cell, [x2, y2]: Cell): boolean =>
10	  x1 === x2 && y1 === y2;
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
16	  neighborsOf(cell).filter((neighbor) =>
17	    liveCells.some((live) => cellsEqual(live, neighbor))
18	  ).length;
19	
20	const survives = (neighborCount: number): boolean =>
21	  neighborCount === 2 || neighborCount === 3;
22	
23	const isDead = (cell: Cell, liveCells: Cell[]): boolean =>
24	  !liveCells.some((live) => cellsEqual(live, cell));
25	
26	const isUnique = (cell: Cell, index: number, cells: Cell[]): boolean =>
27	  cells.findIndex((other) => cellsEqual(other, cell)) === index;
28	
29	const deadNeighborCandidates = (liveCells: Cell[]): Cell[] =>
30	  liveCells
31	    .flatMap(neighborsOf)
32	    .filter((cell) => isDead(cell, liveCells))
33	    .filter(isUnique);
34	
35	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
36	  const survivors = liveCells.filter((cell) =>
37	    survives(countLiveNeighbors(cell, liveCells))
38	  );
39	  const births = deadNeighborCandidates(liveCells).filter(
40	    (cell) => countLiveNeighbors(cell, liveCells) === 3
41	  );
42	  return [...survivors, ...births];
43	};
